import{St as e,ct as t,lt as n,q as r}from"./chunks/framework.CmioJCXl.js";var i=JSON.parse(`{"title":"大学城","description":"大学城校区的觅食指南","frontmatter":{"lang":"zh-CN","title":"大学城","description":"大学城校区的觅食指南"},"headers":[],"relativePath":"en/life/eat/hemc.md","filePath":"en/life/eat/hemc.md","lastUpdated":1784220723000}`),a={name:`en/life/eat/hemc.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="大学城觅食指南" tabindex="-1">大学城觅食指南 <a class="header-anchor" href="#大学城觅食指南" aria-label="Permalink to “大学城觅食指南”">​</a></h1><p>*<em>❤️请留意：以下内容均基于编者个人主观感受，不同人对于美食有不同的追求，如有更多建议，欢迎在评论区留言或者提交pr为此页作贡献ヾ(≧▽≦</em>)o*</p><h2 id="校内" tabindex="-1">校内 <a class="header-anchor" href="#校内" aria-label="Permalink to “校内”">​</a></h2><h3 id="_1-第一饭堂" tabindex="-1">1. 第一饭堂 <a class="header-anchor" href="#_1-第一饭堂" aria-label="Permalink to “1. 第一饭堂”">​</a></h3><ul><li><p>位置：生活区东一门旁边</p></li><li><p>供餐时间：早上9点前，中午11:30 - 13:00，傍晚16:30 - 19:00</p></li></ul><h4 id="各楼层特色" tabindex="-1">各楼层特色 <a class="header-anchor" href="#各楼层特色" aria-label="Permalink to “各楼层特色”">​</a></h4><ul><li><p>一层：学生窗口，商户窗口（炒面、麻辣烫等），便利店，面包店</p></li><li><p>二层：学生窗口（<strong>使用餐盘</strong>），商户窗口</p></li><li><p>三层：教师餐厅（学生也可以在此消费），西北风味餐厅</p></li></ul><h4 id="推荐美食" tabindex="-1">推荐美食 <a class="header-anchor" href="#推荐美食" aria-label="Permalink to “推荐美食”">​</a></h4><ul><li><p>一层：</p><ul><li>个人感觉炒面很不错，很多时候学习得晚其它窗口关了就会去吃【from nanako】</li></ul></li><li><p>二层：</p><ul><li>二楼学生窗口使用餐盘能把油隔开，个人感觉比一楼好【from nanako】</li></ul></li><li><p>三层：</p><ul><li>教师餐厅略贵但比学生餐厅好吃一点【from nanako】</li></ul></li></ul><h3 id="_2-第二饭堂" tabindex="-1">2.第二饭堂 <a class="header-anchor" href="#_2-第二饭堂" aria-label="Permalink to “2.第二饭堂”">​</a></h3><ul><li><p>位置：生活区北一门附近，校医院旁边</p></li><li><p>供餐时间：早上9点前，中午11:30 - 13:00，傍晚16:30 - 19:00</p></li></ul><h4 id="各楼层特色-1" tabindex="-1">各楼层特色 <a class="header-anchor" href="#各楼层特色-1" aria-label="Permalink to “各楼层特色”">​</a></h4><ul><li><p>一层：学生窗口，商户窗口，便利店</p></li><li><p>二层：商户窗口</p></li><li><p>三层：春晖园（外包餐厅）</p></li></ul><h4 id="推荐美食-1" tabindex="-1">推荐美食 <a class="header-anchor" href="#推荐美食-1" aria-label="Permalink to “推荐美食”">​</a></h4><ul><li><p>一层：</p><ul><li>二饭一楼有健康餐，油脂比较少，值得推荐【from nanako】</li><li>一楼的“蛋盖饭”也很不错，但不太推荐淋番茄汁【from nanako】</li></ul></li><li><p>二层：</p><ul><li>二楼的烤肉饭个人感觉还可以【from nanako】</li></ul></li><li><p>三层：</p><ul><li>三层的精品套餐是整层最实惠的，但菜品每天都差不多【from nanako】</li><li>石锅饭虽然好吃，但容易上火【from nanako】</li></ul></li></ul><h3 id="_3-西亚超市" tabindex="-1">3.西亚超市 <a class="header-anchor" href="#_3-西亚超市" aria-label="Permalink to “3.西亚超市”">​</a></h3><ul><li><p>位置：生活区东一门旁边，第一饭堂对面</p></li><li><p>西亚二楼有少量商铺</p></li><li><p>供餐时间：（待补充，应该与超市一同开门）</p></li></ul><h3 id="_4-麦当劳、遇见小面等" tabindex="-1">4.麦当劳、遇见小面等 <a class="header-anchor" href="#_4-麦当劳、遇见小面等" aria-label="Permalink to “4.麦当劳、遇见小面等”">​</a></h3><ul><li><p>位置：篮球场旁的二层小型商业建筑</p></li><li><p>入驻商铺：<strong>麦当劳</strong>，<strong>遇见小面</strong>，<strong>瑞幸</strong>，<strong>包道</strong>，<strong>华园云鲤</strong>，<strong>九龙茶记</strong>，<strong>711</strong></p></li></ul><h2 id="校外" tabindex="-1">校外 <a class="header-anchor" href="#校外" aria-label="Permalink to “校外”">​</a></h2><h3 id="_1-穗石村" tabindex="-1">1.穗石村 <a class="header-anchor" href="#_1-穗石村" aria-label="Permalink to “1.穗石村”">​</a></h3><ul><li>位置：教学区东门外</li></ul><h3 id="_2-「第三饭堂」" tabindex="-1">2.「第三饭堂」 <a class="header-anchor" href="#_2-「第三饭堂」" aria-label="Permalink to “2.「第三饭堂」”">​</a></h3><ul><li><p>指生活区东一门外聚集的小贩</p></li><li><p>卫生状况没有太大保障</p></li><li><p>但有许多校内没有的食物可供选择</p></li></ul><h3 id="_3-大学城其它位置" tabindex="-1">3. 大学城其它位置 <a class="header-anchor" href="#_3-大学城其它位置" aria-label="Permalink to “3. 大学城其它位置”">​</a></h3><ul><li><p>中大旁边的GoGo新天地</p></li><li><p>华师旁边的北亭村</p></li><li><p>广工饭堂</p></li></ul>`,26)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};